import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";

const TimbangMuat = () => {
  const [rfid, setRfid] = useState(null);
  const [form, setForm] = useState({
    jenisBarang: "",
    jumlahBarang: "",
    bruto: "",
    tara: "",
    netto: "",
  });

  useEffect(() => {
    const fetchRFID = async () => {
      try {
        const res = await fetch("http://localhost:5000/api/rfid/latest");
        if (!res.ok) throw new Error("Gagal mengambil data RFID");
        const data = await res.json();
        if (data && data.rfid) {
          setRfid(data.rfid);
        }
      } catch (err) {
        console.error("Error fetching RFID:", err);
      }
    };

    fetchRFID(); // ambil data pertama kali
    const interval = setInterval(fetchRFID, 3000); // polling tiap 3 detik
    return () => clearInterval(interval);
  }, []); // tidak ada warning lagi

  const handleChange = (e) => {
    const { name, value } = e.target;
    let updatedForm = { ...form, [name]: value };

    // hitung otomatis netto
    if (name === "bruto" || name === "tara") {
      const bruto = parseFloat(updatedForm.bruto) || 0;
      const tara = parseFloat(updatedForm.tara) || 0;
      updatedForm.netto = bruto - tara;
    }

    setForm(updatedForm);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!rfid) {
      alert("RFID belum terdeteksi!");
      return;
    }

    const payload = {
      rfid: rfid,
      jenisBarang: form.jenisBarang,
      jumlahBarang: form.jumlahBarang,
      bruto: parseFloat(form.bruto),
      tara: parseFloat(form.tara),
      netto: parseFloat(form.netto),
    };

    try {
      const res = await fetch("http://localhost:5000/api/timbang-muat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (res.ok) {
        alert("Data timbang muat berhasil disimpan!");
        setForm({ jenisBarang: "", jumlahBarang: "", bruto: "", tara: "", netto: "" });
      } else {
        const data = await res.json();
        alert("Gagal menyimpan data: " + data.message);
      }
    } catch (err) {
      console.error("Error:", err);
      alert("Gagal menyimpan data");
    }
  };

  return (
    <div className="flex min-h-screen bg-gradient-to-br from-blue-100 to-purple-200">
      {/* Sidebar */}
      <div className="bg-gray-800 text-white w-64 p-6 flex flex-col justify-between">
        <div>
          <div className="flex flex-col items-center mb-6">
            <img src="/images/admin.png" alt="Admin Icon" className="rounded-full mb-2 w-16 h-16 object-cover" />
            <h2 className="font-semibold text-lg">Admin</h2>
          </div>
          <div className="space-y-6">
            <Link to="/master-data" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Master Data</Link>
            <Link to="/tracking" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Tracking</Link>
            <Link to="/info-driver" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Info Driver</Link>
            <Link to="/checkpoint" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Checkpoint</Link>
            <Link to="/timbang-muat" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Timbang Muat</Link>
          </div>
        </div>
        <div className="space-y-6 mt-6">
          <Link to="/settings" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Settings</Link>
          <Link to="/logout" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Logout</Link>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 p-8">
        <h1 className="text-2xl font-bold mb-6">Timbang Muat</h1>

        <div className={`mb-4 text-white p-3 rounded ${rfid ? 'bg-green-500' : 'bg-red-500'}`}>
          {rfid ? `RFID Terdeteksi: ${rfid}` : 'Silakan scan kartu RFID...'}
        </div>

        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-lg shadow-md space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700">Jenis Barang</label>
            <input type="text" name="jenisBarang" value={form.jenisBarang} onChange={handleChange} required className="mt-1 p-2 border border-gray-300 rounded w-full" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700">Jumlah Barang (satuan/berat)</label>
            <input type="number" name="jumlahBarang" value={form.jumlahBarang} onChange={handleChange} required className="mt-1 p-2 border border-gray-300 rounded w-full" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700">Bruto (kg)</label>
            <input type="number" name="bruto" value={form.bruto} onChange={handleChange} required className="mt-1 p-2 border border-gray-300 rounded w-full" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700">Tara (kg)</label>
            <input type="number" name="tara" value={form.tara} onChange={handleChange} required className="mt-1 p-2 border border-gray-300 rounded w-full" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700">Netto (kg)</label>
            <input type="number" name="netto" value={form.netto} readOnly className="mt-1 p-2 border border-gray-300 rounded w-full bg-gray-100" />
          </div>

          <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700 transition">Simpan</button>
        </form>
      </div>
    </div>
  );
};

export default TimbangMuat;
